<?php
namespace App\Controllers;
use App\Core\Controller; use App\Models\BaseCatalog; use App\Models\InformeModel;
class InformeController extends Controller { public function index():void{$this->requirePermission('Informes de cable');$rows=(new InformeModel)->list();$this->view('informes/index',compact('rows'));} public function form($id=null):void{$this->requirePermission('Informes de cable',$id?'editar':'crear');$m=new BaseCatalog;$inf=new InformeModel;$item=$id?$m->find('informes_cable',(int)$id):null;$cables=$m->fetchAll('SELECT c.*, mc.nombre marca FROM cables c LEFT JOIN marcas_cable mc ON mc.id=c.marca_id WHERE c.deleted_at IS NULL');$supervisores=$m->all('usuarios','nombre');$this->view('informes/form',compact('item','cables','supervisores','inf'));} public function save():void{verify_csrf();$this->requirePermission('Informes de cable',($_POST['id']??'')?'editar':'crear');$m=new BaseCatalog;$jsonFields=['fallas_chaquetas','fallas_enchufe','lugares_falla','causas_probables']; foreach($jsonFields as $f) $_POST[$f]=json_encode($_POST[$f]??[],JSON_UNESCAPED_UNICODE); $cols=['supervisor_id','fecha_recepcion_cable','fecha_entrega_cable','cable_id','origen_cable','estado_informe','rep_ing_mufas_termo','rep_ing_mufa_union','rep_ing_chaquetas','rep_sal_mufas_termo','rep_sal_mufa_union','rep_sal_chaquetas','estado_operativo','destino_cable','tipo_enchufe_entrega','largo_entrega','marca_entrega','capacidad_aislacion_entrega','fallas_chaquetas','fallas_enchufe','lugares_falla','causas_probables','observacion_final']; $p=array_map(fn($c)=>$_POST[$c]??null,$cols); if(!empty($_POST['id'])){$set=implode('=?,',$cols).'=?';$p[] = current_user()['id'];$p[]=$_POST['id'];$m->execSql("UPDATE informes_cable SET $set, actualizado_por=?, updated_at=NOW() WHERE id=?",$p);$id=(int)$_POST['id'];}else{$p[]=current_user()['id'];$p[]=current_user()['id'];$q=rtrim(str_repeat('?,',count($p)),',');$m->execSql('INSERT INTO informes_cable('.implode(',',$cols).',creado_por,actualizado_por,created_at,updated_at) VALUES('.$q.',NOW(),NOW())',$p);$id=(int)\App\Core\App::db()->lastInsertId();}$m->audit('Guardar','Informes de cable',$id,'Informe guardado');flash('success','Informe guardado.');redirect('informes-cable');} public function print($id):void{$this->requirePermission('Informes de cable','imprimir');$m=new BaseCatalog;$item=$m->fetch('SELECT i.*, c.numero_cable FROM informes_cable i JOIN cables c ON c.id=i.cable_id WHERE i.id=?',[$id]);$this->view('informes/print',compact('item'));} }
